#include <stdio.h>
#include <ctype.h>
int max(int a,int b){if(a>b) return a; else return b;}
int main(){
   int i,n,m=0,w=0;
   scanf("%i",&n);
   getchar();
   for(i=0;i<n;i++)
   {
       char c=getchar();
       if(c == ' '){
           m = max(m,w);
           w = 0;
       }else if(isupper(c))
            w++;
   }
   m = max(m,w);
    printf("%i",m);
    return 0-0-0;
}

