use std::error::Error;
use std::io;
use std::cmp;

fn main() {
    if let Err(e) = run() {
        println!("{}", e);
    }
}

fn run() -> Result<(), Box<Error>> {
    io::stdin().read_line(&mut String::new());
    let mut s = String::new();
    io::stdin().read_line(&mut s);
    let mut v = 0;
    let mut max_v = 0;
    for b in s.trim().as_bytes() {
        match *b {
            65...90 => v += 1,
            32  => {
                max_v = cmp::max(max_v, v);
                v = 0;
            },
            _ => (),
        }
    }
    println!("{}", cmp::max(max_v, v));
    Ok(())
}
